#!/usr/bin/env python3
from __future__ import annotations

import argparse
import os
import sys
import tempfile
from pathlib import Path


ROOT_MARKERS = ("manage.py", "ledger", "files", "templates")


class PatchError(RuntimeError):
    pass


def _dedent(value: str) -> str:
    import textwrap
    return textwrap.dedent(value).lstrip("\n")


REPLACEMENTS: dict[str, list[tuple[str, str, str]]] = {}
NEW_FILES: dict[str, str] = {}


def add_replacement(path: str, marker: str, old: str, new: str) -> None:
    REPLACEMENTS.setdefault(path, []).append(
        (marker, _dedent(old), _dedent(new))
    )


def add_new_file(path: str, content: str) -> None:
    NEW_FILES[path] = _dedent(content)


def _atomic_write(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    fd, tmp_name = tempfile.mkstemp(
        prefix=f".{path.name}.",
        dir=str(path.parent),
        text=True,
    )
    try:
        with os.fdopen(fd, "w", encoding="utf-8", newline="") as handle:
            handle.write(content)
            handle.flush()
            os.fsync(handle.fileno())
        os.replace(tmp_name, path)
    except Exception:
        try:
            os.unlink(tmp_name)
        except FileNotFoundError:
            pass
        raise


def _resolve_root(value: str) -> Path:
    root = Path(value).resolve()
    missing = [marker for marker in ROOT_MARKERS if not (root / marker).exists()]
    if missing:
        raise PatchError(
            f"{root} does not look like the MediaCMS repository; missing: "
            + ", ".join(missing)
        )
    return root


def _line_offsets(lines: list[str]) -> list[int]:
    offsets = []
    position = 0
    for line in lines:
        offsets.append(position)
        position += len(line)
    return offsets


def _exact_block_matches(text: str, block: str) -> list[tuple[int, int, str]]:
    matches = []
    start = 0
    while True:
        position = text.find(block, start)
        if position < 0:
            break
        matches.append((position, position + len(block), ""))
        start = position + max(1, len(block))
    return matches


def _indented_block_matches(text: str, block: str) -> list[tuple[int, int, str]]:
    block_lines = block.splitlines(keepends=True)
    text_lines = text.splitlines(keepends=True)
    if not block_lines or not text_lines:
        return []

    first_block_line = block_lines[0]
    if not first_block_line.strip("\r\n"):
        return []

    offsets = _line_offsets(text_lines)
    matches = []
    block_line_count = len(block_lines)

    for line_index, candidate_line in enumerate(text_lines):
        if line_index + block_line_count > len(text_lines):
            break
        if len(candidate_line) <= len(first_block_line):
            continue
        if not candidate_line.endswith(first_block_line):
            continue

        prefix = candidate_line[:-len(first_block_line)]
        if not prefix or not prefix.isspace() or "\n" in prefix or "\r" in prefix:
            continue

        matched = True
        for offset, block_line in enumerate(block_lines):
            actual_line = text_lines[line_index + offset]
            if block_line.strip("\r\n"):
                expected_line = prefix + block_line
                if actual_line != expected_line:
                    matched = False
                    break
            elif actual_line not in {block_line, prefix + block_line}:
                matched = False
                break

        if not matched:
            continue

        start = offsets[line_index]
        end_line_index = line_index + block_line_count - 1
        end = offsets[end_line_index] + len(text_lines[end_line_index])
        matches.append((start, end, prefix))

    return matches


def _block_matches(text: str, block: str) -> list[tuple[int, int, str]]:
    exact = _exact_block_matches(text, block)
    if exact:
        return exact
    return _indented_block_matches(text, block)


def _indent_block(block: str, prefix: str) -> str:
    if not prefix:
        return block
    lines = block.splitlines(keepends=True)
    return "".join(
        prefix + line if line.strip("\r\n") else line
        for line in lines
    )


def _prepare(root: Path) -> dict[Path, str]:
    outputs: dict[Path, str] = {}
    errors: list[str] = []

    for relative_path, operations in REPLACEMENTS.items():
        path = root / relative_path
        if not path.exists():
            errors.append(f"missing file: {relative_path}")
            continue

        original = path.read_text(encoding="utf-8")
        updated = original

        for marker, old, new in operations:
            if marker in updated:
                continue

            new_matches = _block_matches(updated, new)
            if len(new_matches) == 1:
                continue
            if len(new_matches) > 1:
                errors.append(
                    f"{relative_path}: replacement for {marker!r} is ambiguous; "
                    f"found {len(new_matches)} copies"
                )
                continue

            old_matches = _block_matches(updated, old)
            if len(old_matches) != 1:
                errors.append(
                    f"{relative_path}: expected one anchor for {marker!r}, "
                    f"found {len(old_matches)}"
                )
                continue

            start, end, prefix = old_matches[0]
            replacement = _indent_block(new, prefix)
            updated = updated[:start] + replacement + updated[end:]

        outputs[path] = updated

    for relative_path, content in NEW_FILES.items():
        path = root / relative_path
        if path.exists():
            existing = path.read_text(encoding="utf-8")
            if existing != content:
                errors.append(
                    f"{relative_path}: file already exists with different content"
                )
            outputs[path] = existing
        else:
            outputs[path] = content

    if errors:
        raise PatchError("\n".join(errors))

    return outputs


def main() -> int:
    parser = argparse.ArgumentParser(
        description=(
            "Apply the Mt Pelerin browser-event, held-credit, settlement and "
            "strict-expiry integration to the current MediaCMS checkout."
        )
    )
    parser.add_argument(
        "--root",
        default=".",
        help="MediaCMS repository root (default: current directory)",
    )
    parser.add_argument(
        "--check",
        action="store_true",
        help="Validate every anchor without writing files",
    )
    args = parser.parse_args()

    try:
        root = _resolve_root(args.root)
        outputs = _prepare(root)
    except PatchError as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        return 1

    changed = [
        path for path, content in outputs.items()
        if not path.exists() or path.read_text(encoding="utf-8") != content
    ]

    if args.check:
        print(
            "Patch check passed. "
            f"{len(changed)} file(s) would be written."
        )
        return 0

    for path in changed:
        _atomic_write(path, outputs[path])

    print(f"Applied Mt Pelerin held-credit patch to {len(changed)} file(s).")
    print("Next:")
    print("  python manage.py sync_internal_service_users")
    print("  pytest -q tests/ledger/test_mtpelerin_held_credit.py tests/ledger/test_mtpelerin_provider.py")
    print("  restart web and the Celery worker that runs ledger_expire_stale_deposit_sessions")
    return 0


