add_replacement('files/views.py', 'mtpelerin-launch-page-and-event-v1', '@never_cache\n@login_required\ndef wallet_mtpelerin_launch(request, public_id):\n    session = get_object_or_404(\n        DepositSession,\n        public_id=public_id,\n        user=request.user,\n    )\n    provider = (session.metadata or {}).get("payment_provider") or {}\n    if provider.get("key") != MTPERELIN_PROVIDER_KEY:\n        raise Http404\n\n    try:\n        launch = prepare_mtpelerin_browser_launch(\n            session=session,\n            actor=request.user,\n        )\n    except (DjangoValidationError, ImproperlyConfigured) as exc:\n        messages.error(request, _extract_wallet_form_error(exc))\n        return redirect(\n            "wallet_deposit_session",\n            public_id=session.public_id,\n        )\n\n    response = redirect(launch["checkout_url"])\n    response["Cache-Control"] = "no-store, private, max-age=0"\n    response["Pragma"] = "no-cache"\n    response["Expires"] = "0"\n    response["Referrer-Policy"] = "no-referrer"\n    response["X-Content-Type-Options"] = "nosniff"\n    return response\n', '@never_cache\n@login_required\ndef wallet_mtpelerin_launch(request, public_id):\n    session = get_object_or_404(\n        DepositSession,\n        public_id=public_id,\n        user=request.user,\n    )\n    provider = (session.metadata or {}).get("payment_provider") or {}\n    if provider.get("key") != MTPERELIN_PROVIDER_KEY:\n        raise Http404\n\n    try:\n        launch = prepare_mtpelerin_browser_launch(\n            session=session,\n            actor=request.user,\n        )\n        parsed_widget_url = urlparse(launch["checkout_url"])\n        if (\n            parsed_widget_url.scheme != "https"\n            or not parsed_widget_url.netloc\n        ):\n            raise ImproperlyConfigured(\n                "Mt Pelerin widget URL must use HTTPS"\n            )\n        widget_origin = (\n            f"{parsed_widget_url.scheme}://"\n            f"{parsed_widget_url.netloc}"\n        )\n    except (DjangoValidationError, ImproperlyConfigured) as exc:\n        messages.error(request, _extract_wallet_form_error(exc))\n        return redirect(\n            "wallet_deposit_session",\n            public_id=session.public_id,\n        )\n\n    nonce = secrets.token_urlsafe(24)\n    response = render(\n        request,\n        "cms/mtpelerin_launch.html",\n        {\n            "mtpelerin_launch": launch,\n            "mtpelerin_widget_options_json": json.dumps(\n                launch["widget_options"],\n                separators=(",", ":"),\n                ensure_ascii=False,\n            ),\n            "mtpelerin_widget_origin": widget_origin,\n            "mtpelerin_widget_script_url": (\n                f"{widget_origin}/mtp-widget.js"\n            ),\n            "mtpelerin_csp_nonce": nonce,\n        },\n    )\n    response["Cache-Control"] = "no-store, private, max-age=0"\n    response["Pragma"] = "no-cache"\n    response["Expires"] = "0"\n    response["Referrer-Policy"] = "no-referrer"\n    response["X-Content-Type-Options"] = "nosniff"\n    response["X-Frame-Options"] = "DENY"\n    response["Content-Security-Policy"] = (\n        "default-src \'none\'; "\n        f"script-src \'nonce-{nonce}\' {widget_origin}; "\n        f"style-src \'unsafe-inline\' {widget_origin}; "\n        f"img-src {widget_origin} data: blob:; "\n        f"font-src {widget_origin} data:; "\n        f"frame-src {widget_origin}; "\n        f"connect-src \'self\' {widget_origin} "\n        "https://api.mtpelerin.com; "\n        "object-src \'none\'; "\n        "base-uri \'none\'; "\n        "form-action \'self\'; "\n        "frame-ancestors \'none\'"\n    )\n    return response\n\n\n@login_required\n@require_POST\ndef wallet_mtpelerin_event(request, public_id):\n    session = get_object_or_404(\n        DepositSession,\n        public_id=public_id,\n        user=request.user,\n    )\n    if len(request.body or b"") > 16_384:\n        return JsonResponse(\n            {"error": "Mt Pelerin event payload is too large"},\n            status=413,\n        )\n\n    try:\n        payload = json.loads(\n            (request.body or b"{}").decode("utf-8")\n        )\n        if not isinstance(payload, dict):\n            raise DjangoValidationError(\n                "Mt Pelerin event payload must be an object"\n            )\n\n        result = record_mtpelerin_browser_event(\n            session=session,\n            actor=request.user,\n            event_type=payload.get("type") or "",\n            event_data=payload.get("data") or {},\n        )\n    except (\n        UnicodeDecodeError,\n        json.JSONDecodeError,\n        DjangoValidationError,\n        ImproperlyConfigured,\n    ) as exc:\n        return JsonResponse(\n            {"error": _extract_wallet_form_error(exc)},\n            status=400,\n        )\n\n    session.refresh_from_db()\n    session.wallet.refresh_from_db()\n    return JsonResponse(\n        {\n            "ok": True,\n            **result,\n            "deposit": _build_deposit_session_payload(session),\n            "wallet": {\n                "total": int(session.wallet.balance),\n                "held": int(session.wallet.held_balance),\n                "available": get_wallet_available_balance(\n                    session.wallet\n                ),\n            },\n        }\n    )\n')
