add_replacement('templates/cms/deposit_session.html', 'mtpelerin-pending-warning-v1', '<div class="wallet-deposit-ui__warning">\n  <i class="material-icons" aria-hidden="true">info</i>\n  <div>\n    Complete the hosted checkout. Your tokens are credited automatically after the payment is confirmed.\n  </div>\n</div>\n', '<div class="wallet-deposit-ui__warning">\n  <i class="material-icons" aria-hidden="true">info</i>\n  <div>\n    {% if deposit_session.status == "settlement_pending" %}\n      {{ deposit_session.pending_token_amount_display }} tokens are\n      visible in your total balance and locked until the USDC payment\n      is confirmed. This can take several days.\n    {% else %}\n      Complete the hosted checkout. Your tokens are credited\n      automatically after the payment is confirmed.\n    {% endif %}\n  </div>\n</div>\n')
add_new_file('templates/cms/mtpelerin_launch.html', '<!doctype html>\n<html lang="en">\n<head>\n  <meta charset="utf-8">\n  <meta name="viewport" content="width=device-width,initial-scale=1">\n  <title>Mt Pelerin checkout</title>\n  <style nonce="{{ mtpelerin_csp_nonce }}">\n    :root { color-scheme: dark; }\n    body {\n      margin: 0;\n      min-height: 100vh;\n      display: grid;\n      place-items: center;\n      background: #101114;\n      color: #f3f4f6;\n      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\n    }\n    main {\n      width: min(560px, calc(100% - 32px));\n      padding: 32px;\n      box-sizing: border-box;\n      border: 1px solid #2a2d33;\n      border-radius: 16px;\n      background: #17191e;\n      text-align: center;\n    }\n    h1 { margin: 0 0 12px; font-size: 24px; }\n    p { margin: 8px 0; color: #c7cad1; line-height: 1.5; }\n    a { color: #fff; }\n    .status { margin-top: 18px; font-weight: 600; color: #fff; }\n  </style>\n</head>\n<body>\n  <main>\n    <h1>Mt Pelerin bank transfer</h1>\n    <p>\n      Complete the Mt Pelerin flow in this tab. No MediaCMS profile\n      information is pre-filled.\n    </p>\n    <p class="status" id="mtp-status">Opening secure checkout…</p>\n    <p>\n      <a href="{{ mtpelerin_launch.session_url }}">View top-up status</a>\n      ·\n      <a href="{{ mtpelerin_launch.wallet_url }}">Return to wallet</a>\n    </p>\n  </main>\n\n  <form hidden>\n    {% csrf_token %}\n  </form>\n  <script\n    nonce="{{ mtpelerin_csp_nonce }}"\n    src="{{ mtpelerin_widget_script_url }}"\n  ></script>\n  <script nonce="{{ mtpelerin_csp_nonce }}">\n  (function () {\n    "use strict";\n\n    const widgetOrigin = "{{ mtpelerin_widget_origin|escapejs }}";\n    const eventUrl = "{{ mtpelerin_launch.event_url|escapejs }}";\n    const sessionUrl = "{{ mtpelerin_launch.session_url|escapejs }}";\n    const statusNode = document.getElementById("mtp-status");\n    const csrfNode = document.querySelector("[name=csrfmiddlewaretoken]");\n    const widgetOptionsJson = (\n      "{{ mtpelerin_widget_options_json|escapejs }}"\n    );\n    const sentKeys = new Set();\n\n    function parseMessage(value) {\n      if (typeof value === "string") {\n        try {\n          return JSON.parse(value);\n        } catch (error) {\n          return null;\n        }\n      }\n      return value;\n    }\n\n    async function sendEvent(message) {\n      const eventType = String(message.type || "");\n      if (eventType !== "orderCreated" && eventType !== "paymentSubmitted") {\n        return;\n      }\n\n      const data = (\n        message.data && typeof message.data === "object"\n      ) ? message.data : {};\n      const eventKey = eventType + ":" + String(\n        data.paymentId || data.id || ""\n      );\n      if (sentKeys.has(eventKey)) {\n        return;\n      }\n      sentKeys.add(eventKey);\n\n      const response = await fetch(eventUrl, {\n        method: "POST",\n        credentials: "same-origin",\n        headers: {\n          "Content-Type": "application/json",\n          "X-CSRFToken": csrfNode ? csrfNode.value : "",\n          "X-Requested-With": "XMLHttpRequest"\n        },\n        body: JSON.stringify({\n          type: eventType,\n          data: data\n        })\n      });\n\n      const payload = await response.json().catch(function () {\n        return {};\n      });\n      if (!response.ok) {\n        sentKeys.delete(eventKey);\n        throw new Error(payload.error || "Unable to record Mt Pelerin event");\n      }\n\n      if (eventType === "orderCreated") {\n        statusNode.textContent = "Bank transfer instructions generated.";\n      } else {\n        statusNode.textContent = (\n          "Waiting for transaction to complete (can take several days)."\n        );\n        window.setTimeout(function () {\n          window.location.assign(sessionUrl);\n        }, 1200);\n      }\n    }\n\n    window.addEventListener("message", function (event) {\n      if (event.origin !== widgetOrigin) {\n        return;\n      }\n      const message = parseMessage(event.data);\n      if (!message || typeof message !== "object") {\n        return;\n      }\n      sendEvent(message).catch(function (error) {\n        statusNode.textContent = error.message;\n      });\n    });\n\n    try {\n      const options = JSON.parse(widgetOptionsJson);\n      if (typeof window.showMtpModal !== "function") {\n        throw new Error("Mt Pelerin widget failed to load");\n      }\n      window.showMtpModal(options);\n    } catch (error) {\n      statusNode.textContent = error.message;\n    }\n  })();\n  </script>\n</body>\n</html>\n')
add_new_file('tests/ledger/test_mtpelerin_held_credit.py', 'from datetime import timedelta\n\nfrom django.core.exceptions import ValidationError\nfrom django.test import override_settings\nfrom django.utils import timezone\n\nfrom ledger.models import (\n    DepositSession,\n    LedgerHold,\n    LedgerTransaction,\n    ObservedOnchainTransfer,\n)\nfrom ledger.mtpelerin_deposits import (\n    record_mtpelerin_browser_event,\n)\nfrom ledger.services import (\n    credit_confirmed_deposit_session,\n    expire_stale_deposit_sessions,\n)\nfrom tests.ledger.base import BaseLedgerTestCase\n\n\nclass MtPelerinHeldCreditTests(BaseLedgerTestCase):\n    def setUp(self):\n        super().setUp()\n        for codename in [\n            "can_manage_wallet_holds",\n            "can_manage_deposit_sessions",\n            "can_credit_confirmed_deposits",\n            "can_record_onchain_observations",\n            "can_manage_deposit_sweep_jobs",\n        ]:\n            self.grant_perm(self.operator, codename)\n\n        self.settings_override = override_settings(\n            LEDGER_INTERNAL_DEPOSIT_SERVICE_USERNAME=(\n                self.operator.username\n            )\n        )\n        self.settings_override.enable()\n        self.addCleanup(self.settings_override.disable)\n\n        self.session = DepositSession.objects.create(\n            user=self.u1,\n            wallet=self.w1,\n            chain="base",\n            asset_code="USDC",\n            token_contract_address=(\n                "0x1111111111111111111111111111111111111111"\n            ),\n            route_key=(\n                "base:USDC:"\n                "0x1111111111111111111111111111111111111111"\n            ),\n            display_label="Bank transfer (Mt Pelerin · EUR)",\n            derivation_index=987654,\n            derivation_path="m/44\'/60\'/0\'/0/987654",\n            deposit_address=(\n                "0x2222222222222222222222222222222222222222"\n            ),\n            address_derivation_ref="m/44\'/60\'/0\'/0/987654",\n            status=DepositSession.STATUS_AWAITING_PAYMENT,\n            min_amount=1_000_000,\n            expected_onchain_raw_amount=1_000_000,\n            required_confirmations=1,\n            expires_at=timezone.now() + timedelta(seconds=12_345),\n            created_by=self.u1,\n            metadata={\n                "payment_provider": {\n                    "key": "mtpelerin",\n                    "status": "LAUNCH_READY",\n                    "label": "Bank transfer (Mt Pelerin · EUR)",\n                },\n                "payment_method": {\n                    "key": "mtpelerin:eur",\n                    "type": "provider",\n                    "label": "Bank transfer (Mt Pelerin · EUR)",\n                },\n                "token_pack": self.default_token_pack_snapshot(),\n                "amount_unit": "canonical_stable",\n                "expected_canonical_stable_amount": 1_000_000,\n                "expected_route_raw_amount": "1000000",\n            },\n        )\n\n    def _submit_payment(self):\n        return record_mtpelerin_browser_event(\n            session=self.session,\n            actor=self.u1,\n            event_type="paymentSubmitted",\n            event_data={\n                "paymentType": "bankTransfer",\n                "paymentId": "payment-123",\n                "email": "must-not-be-stored@example.invalid",\n            },\n        )\n\n    def test_payment_submitted_credits_total_and_holds_same_amount(self):\n        result = self._submit_payment()\n\n        self.w1.refresh_from_db()\n        self.session.refresh_from_db()\n        pending = self.session.metadata["mtpelerin_pending_credit"]\n\n        self.assertEqual(\n            result["pending_credit_status"],\n            "held",\n        )\n        self.assertEqual(\n            self.w1.balance,\n            self.default_token_pack.token_amount,\n        )\n        self.assertEqual(\n            self.w1.held_balance,\n            self.default_token_pack.token_amount,\n        )\n        self.assertEqual(\n            self.w1.balance - self.w1.held_balance,\n            0,\n        )\n        self.assertEqual(pending["status"], "held")\n        self.assertEqual(\n            pending["expires_at"],\n            self.session.expires_at.isoformat(),\n        )\n        self.assertNotIn(\n            "email",\n            self.session.metadata["mtpelerin_browser_events"][\n                "payment_submitted"\n            ],\n        )\n\n    def test_payment_submitted_is_idempotent(self):\n        first = self._submit_payment()\n        second = self._submit_payment()\n\n        self.w1.refresh_from_db()\n        self.assertEqual(\n            first["pending_credit_status"],\n            second["pending_credit_status"],\n        )\n        self.assertEqual(\n            self.w1.balance,\n            self.default_token_pack.token_amount,\n        )\n        self.assertEqual(\n            self.w1.held_balance,\n            self.default_token_pack.token_amount,\n        )\n        self.assertEqual(\n            LedgerTransaction.objects.filter(\n                external_id=(\n                    "mtpelerin-pending-credit:"\n                    f"{self.session.public_id}"\n                )\n            ).count(),\n            1,\n        )\n        self.assertEqual(\n            LedgerHold.objects.filter(\n                metadata__deposit_session_public_id=str(\n                    self.session.public_id\n                )\n            ).count(),\n            1,\n        )\n\n    def test_confirmed_usdc_releases_hold_without_second_user_credit(self):\n        self._submit_payment()\n        pending_txn_id = (\n            self.session.__class__.objects.get(\n                id=self.session.id\n            ).metadata["mtpelerin_pending_credit"]["ledger_txn_id"]\n        )\n        observed = ObservedOnchainTransfer.objects.create(\n            deposit_session=self.session,\n            event_key="base:0xabc:0",\n            chain=self.session.chain,\n            txid="0xabc",\n            log_index=0,\n            block_number=100,\n            detected_block_number=100,\n            from_address=(\n                "0x3333333333333333333333333333333333333333"\n            ),\n            to_address=self.session.deposit_address,\n            token_contract_address=(\n                self.session.token_contract_address\n            ),\n            asset_code=self.session.asset_code,\n            amount=1_000_000,\n            onchain_raw_amount=1_000_000,\n            confirmations=1,\n            detection_method="event",\n            status=ObservedOnchainTransfer.STATUS_CONFIRMED,\n            confirmed_at=timezone.now(),\n            raw_payload={\n                "amount_unit": "canonical_stable",\n                "canonical_stable_amount": 1_000_000,\n                "onchain_raw_amount": "1000000",\n            },\n        )\n\n        credit_confirmed_deposit_session(\n            actor=self.operator,\n            deposit_session=self.session,\n            observed_transfer=observed,\n        )\n\n        self.w1.refresh_from_db()\n        self.session.refresh_from_db()\n        observed.refresh_from_db()\n        pending = self.session.metadata["mtpelerin_pending_credit"]\n\n        self.assertEqual(\n            self.w1.balance,\n            self.default_token_pack.token_amount,\n        )\n        self.assertEqual(self.w1.held_balance, 0)\n        self.assertEqual(\n            self.session.status,\n            DepositSession.STATUS_CREDITED,\n        )\n        self.assertEqual(\n            self.session.credited_ledger_txn_id,\n            pending_txn_id,\n        )\n        self.assertEqual(pending["status"], "settled")\n        self.assertEqual(\n            observed.credited_ledger_txn_id,\n            pending_txn_id,\n        )\n\n    def test_expiry_releases_hold_and_reverses_pending_credit(self):\n        self._submit_payment()\n        self.session.refresh_from_db()\n        self.session.expires_at = timezone.now() - timedelta(seconds=1)\n        self.session.save(update_fields=["expires_at", "updated_at"])\n\n        expired_count = expire_stale_deposit_sessions(\n            actor=self.operator,\n            limit=10,\n        )\n\n        self.w1.refresh_from_db()\n        self.session.refresh_from_db()\n        pending = self.session.metadata["mtpelerin_pending_credit"]\n\n        self.assertEqual(expired_count, 1)\n        self.assertEqual(self.w1.balance, 0)\n        self.assertEqual(self.w1.held_balance, 0)\n        self.assertEqual(\n            self.session.status,\n            DepositSession.STATUS_EXPIRED,\n        )\n        self.assertEqual(pending["status"], "expired")\n        self.assertTrue(\n            LedgerTransaction.objects.filter(\n                external_id=(\n                    "mtpelerin-pending-expiry:"\n                    f"{self.session.public_id}"\n                ),\n                status=LedgerTransaction.STATUS_REVERSED,\n            ).exists()\n        )\n        self.assertFalse(\n            LedgerHold.objects.filter(\n                id=pending["hold_id"],\n                released=False,\n            ).exists()\n        )\n\n    def test_payment_submitted_after_session_deadline_is_rejected(self):\n        self.session.expires_at = timezone.now() - timedelta(seconds=1)\n        self.session.save(update_fields=["expires_at", "updated_at"])\n\n        with self.assertRaisesMessage(\n            ValidationError,\n            "Mt Pelerin session has expired",\n        ):\n            self._submit_payment()\n\n        self.w1.refresh_from_db()\n        self.assertEqual(self.w1.balance, 0)\n        self.assertEqual(self.w1.held_balance, 0)\n')


if __name__ == "__main__":
    raise SystemExit(main())
